glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float uTime;
uniform float grainScale;
uniform float warmth;
uniform float axisStrength;
uniform float edgeDarken;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123); }
float noise(vec2 p){ vec2 i=floor(p); vec2 f=fract(p); vec2 u=f*f*(3.0-2.0*f); return mix(mix(hash(i),hash(i+vec2(1.0,0.0)),u.x),mix(hash(i+vec2(0.0,1.0)),hash(i+vec2(1.0,1.0)),u.x),u.y); }
void main(){
 vec2 p = vUv * 2.0 - 1.0;
 float n1 = noise(vUv * grainScale);
 float n2 = noise(vUv * grainScale * 0.23 + vec2(4.0, 1.7));
 vec3 red = vec3(0.70, 0.23, 0.13);
 vec3 orange = vec3(0.90, 0.45, 0.18);
 vec3 ochre = vec3(0.75, 0.38, 0.12);
 vec3 col = mix(red, orange, 0.28 + 0.22*n2*warmth);
 col = mix(col, ochre, 0.12*smoothstep(-0.95, 0.7, p.y));
 float brush = (n1 - 0.5) * 0.075 + (n2 - 0.5) * 0.055;
 float axis = 1.0 - smoothstep(0.0, 0.014, abs(p.x));
 col += vec3(0.82, 0.58, 0.20) * axis * axisStrength;
 float edge = smoothstep(0.72, 1.25, length(p * vec2(0.78, 1.0)));
 col *= 1.0 - edge * edgeDarken;
 col += brush;
 gl_FragColor = vec4(clamp(col, 0.0, 1.0), 1.0);
}

