glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float uTime;
uniform float baseWidth;
uniform float height;
uniform float fillOpacity;
uniform float bandWidth;
float hash(vec2 p){ return fract(sin(dot(p, vec2(19.19, 73.23))) * 24634.6345); }
float lineDist(vec2 p, vec2 a, vec2 b){ vec2 pa=p-a; vec2 ba=b-a; float h=clamp(dot(pa,ba)/dot(ba,ba),0.0,1.0); return length(pa-ba*h); }
void main(){
 vec2 p = vUv * 2.0 - 1.0;
 vec2 a = vec2(-baseWidth*0.5, -0.96);
 vec2 b = vec2(baseWidth*0.5, -0.96);
 vec2 c = vec2(0.0, -0.96 + height);
 float s1 = (b.x-a.x)*(p.y-a.y)-(b.y-a.y)*(p.x-a.x);
 float s2 = (c.x-b.x)*(p.y-b.y)-(c.y-b.y)*(p.x-b.x);
 float s3 = (a.x-c.x)*(p.y-c.y)-(a.y-c.y)*(p.x-c.x);
 float inside = step(0.0, s1) * step(0.0, s2) * step(0.0, s3);
 float d = min(lineDist(p,a,c), lineDist(p,b,c));
 float band = 1.0 - smoothstep(bandWidth, bandWidth + 0.018, d);
 float grain = hash(floor(vUv * 180.0));
 vec3 cream = vec3(0.93, 0.82, 0.58) + (grain - 0.5) * 0.055;
 vec3 gold = vec3(0.86, 0.62, 0.20);
 float lowerFade = smoothstep(-0.98, -0.72, p.y);
 float alpha = inside * fillOpacity * 0.72 * lowerFade + band * 0.68;
 vec3 col = mix(cream, gold, band * 0.42);
 gl_FragColor = vec4(clamp(col,0.0,1.0), clamp(alpha,0.0,0.92));
}

