glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float uTime;
uniform float lineWidth;
uniform float blueWeight;
uniform float asymmetry;
uniform float opacity;
float ring(vec2 p, vec2 c, float r, float w){ return 1.0 - smoothstep(w, w + 0.006, abs(length(p-c)-r)); }
float segRing(vec2 p, vec2 c, float r, float w, float start, float end){ float a=atan(p.y-c.y,p.x-c.x); float m=smoothstep(start,start+0.08,a)*(1.0-smoothstep(end-0.08,end,a)); return ring(p,c,r,w)*m; }
float lineDist(vec2 p, vec2 a, vec2 b){ vec2 pa=p-a; vec2 ba=b-a; float h=clamp(dot(pa,ba)/dot(ba,ba),0.0,1.0); return length(pa-ba*h); }
void main(){
 vec2 p = vUv * 2.0 - 1.0;
 float l = 0.0;
 vec2 lc = vec2(-0.31, 0.20);
 vec2 rc = vec2(0.39 + asymmetry*0.12, 0.15);
 l += ring(p, lc, 0.18, lineWidth) * 0.82;
 l += segRing(p, lc + vec2(-0.025,0.018), 0.245, lineWidth*0.82, -2.8, 1.25) * 0.55;
 l += ring(p, rc, 0.145, lineWidth*0.9) * 0.70;
 l += segRing(p, rc + vec2(0.035,-0.01), 0.225, lineWidth*0.78, -1.35, 2.65) * 0.52;
 l += (1.0 - smoothstep(lineWidth, lineWidth + 0.006, abs(lineDist(p, vec2(-0.55, -0.11), vec2(0.56, -0.05))))) * 0.28;
 l += (1.0 - smoothstep(lineWidth*0.9, lineWidth*0.9 + 0.006, abs(lineDist(p, vec2(-0.18, -0.35), vec2(0.13, 0.55))))) * 0.24;
 vec3 gold = vec3(0.82,0.57,0.17);
 vec3 blue = vec3(0.16,0.43,0.60);
 float blueMask = ring(p, lc, 0.18, lineWidth*1.4) + ring(p, rc, 0.145, lineWidth*1.4);
 vec3 col = mix(gold, blue, clamp(blueMask * blueWeight, 0.0, 1.0));
 gl_FragColor = vec4(col, clamp(l * opacity, 0.0, 0.78));
}

