glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float centerX;
uniform float centerY;
uniform float scale;
uniform float roughness;
float hash(vec2 p){ return fract(sin(dot(p, vec2(41.0, 289.0))) * 9514.31); }
float box(vec2 p, vec2 b){ vec2 d=abs(p)-b; return length(max(d,0.0))+min(max(d.x,d.y),0.0); }
void main(){
 vec2 p = (vUv * 2.0 - 1.0 - vec2(centerX, centerY)) / scale;
 float mask = 0.0;
 mask += 1.0 - smoothstep(0.0, 0.055, box(p - vec2(-0.28, 0.05), vec2(0.20, 0.035)));
 mask += 1.0 - smoothstep(0.0, 0.055, box(p - vec2(0.00, -0.02), vec2(0.18, 0.035)));
 mask += 1.0 - smoothstep(0.0, 0.055, box(p - vec2(0.25, 0.06), vec2(0.14, 0.032)));
 float chip = hash(floor((p + 1.3) * 12.0));
 mask *= smoothstep(0.18, 0.18 + roughness, chip);
 vec3 paleGold = vec3(0.96, 0.80, 0.36);
 vec3 dryEdge = vec3(0.74, 0.49, 0.16);
 vec3 col = mix(dryEdge, paleGold, 0.68 + 0.32*chip);
 gl_FragColor = vec4(col, clamp(mask * 0.86, 0.0, 0.86));
}
